import argparse
import json
import signal
import sys
import time
from datetime import datetime

import pika


RABBITMQ_HOST = "localhost"
RABBITMQ_PORT = 5672
QUEUE_NAME = "task_queue"


def create_connection():
    credentials = pika.PlainCredentials("guest", "guest")
    parameters = pika.ConnectionParameters(
        host=RABBITMQ_HOST,
        port=RABBITMQ_PORT,
        credentials=credentials,
        heartbeat=60,
        blocked_connection_timeout=300,
    )
    return pika.BlockingConnection(parameters)


def declare_queue(channel, queue_name=QUEUE_NAME):
    channel.queue_declare(queue=queue_name, durable=True)


def publish_task(task, queue_name=QUEUE_NAME):
    connection = create_connection()
    channel = connection.channel()
    declare_queue(channel, queue_name)

    message = {
        "task": task,
        "created_at": datetime.utcnow().isoformat() + "Z",
    }

    channel.basic_publish(
        exchange="",
        routing_key=queue_name,
        body=json.dumps(message),
        properties=pika.BasicProperties(
            delivery_mode=2,
            content_type="application/json",
        ),
    )

    print(f"Published task to '{queue_name}': {message}")
    connection.close()


class TaskConsumer:
    def __init__(self, queue_name=QUEUE_NAME):
        self.queue_name = queue_name
        self.connection = None
        self.channel = None
        self._stopping = False

    def connect(self):
        self.connection = create_connection()
        self.channel = self.connection.channel()
        declare_queue(self.channel, self.queue_name)
        self.channel.basic_qos(prefetch_count=1)

    def process_task(self, body):
        try:
            payload = json.loads(body.decode("utf-8"))
        except Exception:
            payload = {"task": body.decode("utf-8", errors="replace")}

        task = payload.get("task")
        print(f"Processing task: {task}")
        time.sleep(2)
        print(f"Completed task: {task}")

    def on_message(self, ch, method, properties, body):
        try:
            self.process_task(body)
            ch.basic_ack(delivery_tag=method.delivery_tag)
        except Exception as exc:
            print(f"Error processing message: {exc}", file=sys.stderr)
            ch.basic_nack(delivery_tag=method.delivery_tag, requeue=True)

    def start(self):
        self.connect()
        self.channel.basic_consume(
            queue=self.queue_name,
            on_message_callback=self.on_message,
        )
        print(f"Waiting for messages on '{self.queue_name}'. Press Ctrl+C to exit.")
        try:
            self.channel.start_consuming()
        except KeyboardInterrupt:
            self.stop()

    def stop(self):
        if self._stopping:
            return
        self._stopping = True
        print("Stopping consumer...")
        try:
            if self.channel and self.channel.is_open:
                self.channel.stop_consuming()
        except Exception:
            pass
        try:
            if self.connection and self.connection.is_open:
                self.connection.close()
        except Exception:
            pass


def main():
    parser = argparse.ArgumentParser(description="RabbitMQ task publisher/consumer")
    subparsers = parser.add_subparsers(dest="command", required=True)

    pub_parser = subparsers.add_parser("publish", help="Publish a task message")
    pub_parser.add_argument("task", help="Task payload to send")
    pub_parser.add_argument("--queue", default=QUEUE_NAME, help="Queue name")

    con_parser = subparsers.add_parser("consume", help="Consume task messages")
    con_parser.add_argument("--queue", default=QUEUE_NAME, help="Queue name")

    args = parser.parse_args()

    if args.command == "publish":
        publish_task(args.task, args.queue)
    elif args.command == "consume":
        consumer = TaskConsumer(args.queue)

        def handle_signal(signum, frame):
            consumer.stop()
            sys.exit(0)

        signal.signal(signal.SIGINT, handle_signal)
        signal.signal(signal.SIGTERM, handle_signal)
        consumer.start()


if __name__ == "__main__":
    main()